import { describe, it, expect, beforeAll } from 'vitest';
import { transpile } from './babelfish';
import {
  buildPolyglotFnInput,
  id,
  callArg,
  member,
  varDecl,
  ret,
  initPolyglotBettiWasm,
} from './polyglot-betti-bridge';

describe('Babelfish Phase 3 - Cross-Language Optimizing Transpiler', () => {
  let wasmLoaded = false;

  beforeAll(async () => {
    try {
      const pkgPath = require.resolve('../../gnosis-betti-wasm/pkg/gnosis_betti_wasm.js').replace(/\\/g, '/');
      await initPolyglotBettiWasm('file://' + pkgPath);
      wasmLoaded = true;
    } catch {
      // WASM not built or unavailable in this test env.
    }
  });

  it('completes the pipeline without optimizations (native Rust conversion)', () => {
    if (!wasmLoaded) return;

    // Source (Java) -> Polyglot JSON AST
    const input = buildPolyglotFnInput(
      'java',
      'fetchUser',
      ['uid'],
      [
        varDecl(
          ['res'],
          callArg(member(id('db'), 'get'), [id('uid')]),
          { source: 'Object res = db.get(uid);' }
        ),
        ret(id('res'), { source: 'return res;' }),
      ]
    );

    // Act: Transpile back down to Rust seamlessly
    const result = transpile(input, { targetLanguage: 'rust', optimize: false });

    expect(result.synthesizedCode).toContain('let res = db.get(uid).await;');
    expect(result.emissionMethod).toBe('native_formatter');
    expect(result.optimizationsApplied).toBeUndefined();
    expect(result.topologySource.length).toBeGreaterThan(0);

    // Verify .gnot receipt (the pure "soul") was generated
    expect(result.gnotReceipt).toBeDefined();
    expect(result.gnotReceipt).toContain('# fetchUser.gnot');
    expect(result.gnotReceipt).toContain('is fetchUser');
    expect(result.gnotReceipt).toContain('res <- java, do(db)');
  });

  it('verifies optimization suggestions are detected and bound mid-translation', () => {
    if (!wasmLoaded) return;

    // Simulate an input AST that takes > 500ms natively
    const input = buildPolyglotFnInput(
      'python',
      'heavyCompute',
      ['data'],
      [
        varDecl(
          ['r'],
          callArg(id('slow_math_loop'), [id('data')]),
          { source: 'r = slow_math_loop(data)' }
        ),
        ret(id('r'), { source: 'return r' }),
      ]
    );

    // Act: Transpile with `.gg` topological optimizations fully engaged
    const result = transpile(input, { targetLanguage: 'go', optimize: true });

    // The optimization analyzer will flag `slow_math_loop` running >500ms.
    // Python -> suggested RACE with Go.
    expect(result.optimizationsApplied).toBeDefined();
    expect(result.optimizationsApplied?.length).toBeGreaterThan(0);
    expect(result.optimizationsApplied![0]).toContain("RACE with go implementation");
    
    // We expect the go synthesizer to naturally emit `r := slow_math_loop(data)`
    expect(result.synthesizedCode).toContain('r := slow_math_loop(data)');
    expect(result.emissionMethod).toBe('native_formatter');
  });

  it('aborts safely if attempting to synthesize natively into an unsupported language representation', () => {
    if (!wasmLoaded) return;

    const input = buildPolyglotFnInput(
      'python',
      'someFunc',
      [],
      [ret(id('foo'))]
    );

    // Target a language that doesn't natively map structural topology components yet (e.g., C++)
    expect(() => {
      transpile(input, { targetLanguage: 'cpp' });
    }).toThrowError("Target language 'cpp' does not have a native representation yet");
  });

  it('performs exact source-to-source transpilation across all supported native targets', () => {
    if (!wasmLoaded) return;
    
    const input = buildPolyglotFnInput(
      'python',
      'user_service',
      ['request'],
      [
        varDecl(['auth'], callArg(id('verify'), [id('request')])),
        varDecl(['user'], callArg(member(id('db'), 'fetch'), [id('auth')])),
        ret(id('user'))
      ]
    );

    // Python target
    const pyResult = transpile(input, { targetLanguage: 'python' });
    expect(pyResult.synthesizedCode).toContain('auth = await verify(request)');
    expect(pyResult.synthesizedCode).toContain('user = await db.fetch(auth)');
    expect(pyResult.synthesizedCode).toContain('return user');

    // Go target
    const goResult = transpile(input, { targetLanguage: 'go' });
    expect(goResult.synthesizedCode).toContain('auth := verify(request)');
    expect(goResult.synthesizedCode).toContain('user := db.fetch(auth)');
    expect(goResult.synthesizedCode).toContain('return user');

    // Rust target
    const rsResult = transpile(input, { targetLanguage: 'rust' });
    expect(rsResult.synthesizedCode).toContain('let auth = verify(request).await;');
    expect(rsResult.synthesizedCode).toContain('let user = db.fetch(auth).await;');
    expect(rsResult.synthesizedCode).toContain('return user;');

    // Gnot optimal receipt representation
    const gnotResult = transpile(input, { targetLanguage: 'gnot' });
    expect(gnotResult.synthesizedCode).toContain('using');
    expect(gnotResult.synthesizedCode).toContain('python');
    expect(gnotResult.synthesizedCode).toContain('do(verify)');
    expect(gnotResult.gnotReceipt).toBe(gnotResult.synthesizedCode); // Gnot language target maps directly to receipt natively.
  });
});
